const PB_URL=($('Config').first().json.pbUrl||'').replace(/\/+$/,'');
const token=$('PB Auth').first().json.token; const pbH={Authorization:token};
const body=($('Webhook').first().json.body)||{};
const fedId=body.id; const limit=body.limit?Number(body.limit):0;
let items=[]; let page=1;
while(true){ const r=await this.helpers.httpRequest({method:'GET',url:PB_URL+'/api/collections/clubs/records',qs:{filter:'federation="'+fedId+'" && detail_url!=""',perPage:200,page,fields:'id,name,detail_url'},headers:pbH,json:true}); items=items.concat(r.items||[]); if(page>=(r.totalPages||1))break; page++; }
if(limit>0) items=items.slice(0,limit);
