const PB_URL=($('Config').first().json.pbUrl||'').replace(/\/+$/,'');
const token=$('PB Auth').first().json.token; const pbH={Authorization:token};
const clubs=$('List clubs').all().map(i=>i.json);
if(clubs.length===1 && clubs[0].__skip) return [{json:{ok:false,note:clubs[0].note}}];
const agents=$('Extract contact').all().map(i=>i.json);
const isEmail=(e)=>/^[^@\s]+@[^@\s]+\.[^@\s]+$/.test(e);
const findContact=async(e)=>{const r=await this.helpers.httpRequest({method:'GET',url:PB_URL+'/api/collections/contacts/records',qs:{filter:"(email='"+e.replace(/'/g,'')+"')",perPage:1},headers:pbH,json:true});return (r.items&&r.items[0])||null;};
const parse=(raw0)=>{let raw=String(raw0||'').trim().replace(/^```(json)?/i,'').replace(/```\s*$/,'').trim();try{const p=JSON.parse(raw);if(p&&Array.isArray(p.contacts))return p.contacts;}catch(e){}const out=[];const st=[];for(let i=0;i<raw.length;i++){const ch=raw[i];if(ch==='{')st.push(i);else if(ch==='}'){const s=st.pop();if(s!=null){try{const o=JSON.parse(raw.slice(s,i+1));if(o&&typeof o==='object'&&!Array.isArray(o)&&('email' in o))out.push(o);}catch(_){}}}}return out;};
let created=0,patched=0,clubsWith=0;const errors=[];
for(let i=0;i<clubs.length;i++){const cl=clubs[i];const ag=agents[i]||{};const cts=parse(ag.output);let saved=0;
  for(const ct of cts){const email=String((ct&&ct.email)||'').trim().toLowerCase();if(!email||!isEmail(email))continue;
    const nm=String((ct&&ct.name)||'').trim(),pos=String((ct&&ct.position)||'').trim(),ph=String((ct&&ct.phone)||'').trim();
    try{await this.helpers.httpRequest({method:'POST',url:PB_URL+'/api/collections/contacts/records',headers:pbH,body:{club:cl.clubId,email,name:nm,position:pos,phone:ph,source_url:cl.detailUrl,verification_status:'unverified'},json:true});created++;saved++;}
    catch(e){try{const ex=await findContact(email);if(ex){const p={};if(!ex.club)p.club=cl.clubId;if(nm&&!ex.name)p.name=nm;if(pos&&!ex.position)p.position=pos;if(ph&&!ex.phone)p.phone=ph;if(!ex.source_url)p.source_url=cl.detailUrl;if(Object.keys(p).length){await this.helpers.httpRequest({method:'PATCH',url:PB_URL+'/api/collections/contacts/records/'+ex.id,headers:pbH,body:p,json:true});patched++;saved++;}}}catch(_){if(errors.length<8)errors.push({email});}}
  }
  if(saved>0){clubsWith++;try{await this.helpers.httpRequest({method:'PATCH',url:PB_URL+'/api/collections/clubs/records/'+cl.clubId,headers:pbH,body:{status:'contacts_found'},json:true});}catch(_){}}
}
return [{json:{ok:true,clubs:clubs.length,contactsCreated:created,contactsPatched:patched,clubsWithContacts:clubsWith,errors}}];
